<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">mode</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;AUTO&quot;</span></span>
